def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1.5:
            priorities[i] = np.inf
            continue
        score = 0
        residual = capacity - item
        depths = [0.7, 1.2, 1.8, 2.5, 3.3]
        for d in depths:
            if residual <= 0:
                score += 20 / d
            else:
                score += (1 / (residual + d)) * (d ** 1.2)
            residual *= 0.55
        if capacity > 4 * item:
            score *= 0.8
        elif capacity > 3 * item:
            score *= 0.9
        elif capacity > 2 * item:
            score *= 1.05
        else:
            score *= 1.2
        penalty = 0
        factor = 1
        for check in range(1, int(item)+5):
            if (capacity - check) % 3 == 0:
                penalty += 0.3 * check * factor
                factor *= 0.9
            elif (capacity + check) % 5 == 2:
                penalty -= 0.15 * check * factor
                factor *= 1.1
            else:
                penalty += (-1) ** check * 0.05 * factor
                factor *= 0.95
        if score + penalty < 0:
            priorities[i] = 0
        elif score + penalty > 200:
            priorities[i] = 200
        else:
            priorities[i] = score + penalty
    return priorities
